Here’s a TekAutomate Steps UI flow for your MSO4/5/6 Series scope using pyvisa backend, following your requirements. All commands are based on Tektronix programmer manuals and verified SCPI syntax.

```json
{
  "steps": [
    {
      "type": "connect",
      "id": "connect_scope",
      "params": {
        "device_type": "SCOPE",
        "model_family": "MSO4/5/6 Series",
        "backend": "pyvisa"
      }
    },
    {
      "type": "write",
      "id": "ch1_setup",
      "params": {
        "command": "CH1:SCALE 0.05; CH1:COUP DC; CH1:IMP 50"
      }
    },
    {
      "type": "write",
      "id": "ch2_setup",
      "params": {
        "command": "CH2:SCALE 1.0; CH2:COUP DC"
      }
    },
    {
      "type": "write",
      "id": "trigger_setup",
      "params": {
        "command": "TRIG:A:EDGE:SOU CH1; TRIG:A:EDGE:SLO RIS; TRIG:A:LEV 0.025; TRIG:A:MODE NORM; TRIG:A:HOLD 1E-4"
      }
    },
    {
      "type": "write",
      "id": "acq_avg_setup",
      "params": {
        "command": "ACQ:MODE AVER; ACQ:NUMAVG 128"
      }
    },
    {
      "type": "write",
      "id": "clear_meas",
      "params": {
        "command": "MEAS:CLE"
      }
    },
    {
      "type": "write",
      "id": "add_mean",
      "params": {
        "command": "MEASUrement:ADDMeas MEAN,CH1"
      }
    },
    {
      "type": "write",
      "id": "add_rms",
      "params": {
        "command": "MEASUrement:ADDMeas RMS,CH1"
      }
    },
    {
      "type": "write",
      "id": "add_pk2pk",
      "params": {
        "command": "MEASUrement:ADDMeas PK2PK,CH1"
      }
    },
    {
      "type": "write",
      "id": "add_high",
      "params": {
        "command": "MEASUrement:ADDMeas HIGH,CH1"
      }
    },
    {
      "type": "write",
      "id": "add_low",
      "params": {
        "command": "MEASUrement:ADDMeas LOW,CH1"
      }
    },
    {
      "type": "write",
      "id": "add_pos_overshoot",
      "params": {
        "command": "MEASUrement:ADDMeas POSITIVEOVERSHOOT,CH1"
      }
    },
    {
      "type": "write",
      "id": "add_freq_ch2",
      "params": {
        "command": "MEASUrement:ADDMeas FREQUENCY,CH2"
      }
    },
    {
      "type": "sleep",
      "id": "wait_acq",
      "params": {
        "seconds": 2
      }
    },
    {
      "type": "query",
      "id": "query_mean",
      "params": {
        "command": "MEASUrement:MEAS1:RESUlts:CURRent:VALue?"
      }
    },
    {
      "type": "query",
      "id": "query_rms",
      "params": {
        "command": "MEASUrement:MEAS2:RESUlts:CURRent:VALue?"
      }
    },
    {
      "type": "query",
      "id": "query_pk2pk",
      "params": {
        "command": "MEASUrement:MEAS3:RESUlts:CURRent:VALue?"
      }
    },
    {
      "type": "query",
      "id": "query_high",
      "params": {
        "command": "MEASUrement:MEAS4:RESUlts:CURRent:VALue?"
      }
    },
    {
      "type": "query",
      "id": "query_low",
      "params": {
        "command": "MEASUrement:MEAS5:RESUlts:CURRent:VALue?"
      }
    },
    {
      "type": "query",
      "id": "query_pos_overshoot",
      "params": {
        "command": "MEASUrement:MEAS6:RESUlts:CURRent:VALue?"
      }
    },
    {
      "type": "query",
      "id": "query_freq_ch2",
      "params": {
        "command": "MEASUrement:MEAS7:RESUlts:CURRent:VALue?"
      }
    },
    {
      "type": "save_waveform",
      "id": "save_ch1_csv",
      "params": {
        "channel": "CH1",
        "file_format": "CSV",
        "file_path": "D:/CH1_waveform.csv"
      }
    },
    {
      "type": "save_screenshot",
      "id": "save_screenshot",
      "params": {
        "file_path": "D:/scope_screenshot.png"
      }
    },
    {
      "type": "disconnect",
      "id": "disconnect_scope",
      "params": {}
    }
  ]
}
```

This flow connects to the scope, configures channels and trigger, sets up averaging, adds and queries all requested measurements, saves the CH1 waveform as CSV, takes a screenshot, and disconnects. Adjust file paths as needed for your instrument.

